import 'package:flutter_secure_storage/flutter_secure_storage.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  final FlutterSecureStorage _secureStorage = FlutterSecureStorage();
  SharedPreferences? _prefs;

  Future<void> init() async {
    _prefs = await SharedPreferences.getInstance();
  }

  Future<void> login(String token, Map<String, dynamic> userData) async {
    await _secureStorage.write(key: 'auth_token', value: token);
    await _secureStorage.write(key: 'user_id', value: userData['id'].toString());
    await _prefs?.setString('username', userData['username']);
  }

  Future<void> logout() async {
    await _secureStorage.delete(key: 'auth_token');
    await _secureStorage.delete(key: 'user_id');
    await _prefs?.remove('username');
  }

  Future<String?> getAuthToken() async {
    return await _secureStorage.read(key: 'auth_token');
  }

  Future<Map<String, dynamic>?> getUserData() async {
    String? userId = await _secureStorage.read(key: 'user_id');
    String? username = _prefs?.getString('username');

    if (userId != null && username != null) {
      return {'id': userId, 'username': username};
    }
    return null;
  }

  Future<bool> isLoggedIn() async {
    return (await getAuthToken()) != null;
  }
}